import React, { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { supabase } from '../../lib/supabaseClient'
import { IMAGES } from '../../constants/images'

export const Dashboard: React.FC = () => {
  const [profile, setProfile] = useState<any>(null)
  const [upcomingSessions, setUpcomingSessions] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [stats, setStats] = useState({
    sessionsJoined: 0,
    playersFound: 0,
    listings: 0,
    posts: 0
  })

  useEffect(() => {
    loadData()
  }, [])

  const loadData = async () => {
    const { data: { user } } = await supabase.auth.getUser()

    const { data: profileData } = await supabase
      .from('users')
      .select('*')
      .eq('id', user?.id)
      .single()
    setProfile(profileData)

    const { count: sessionsCount } = await supabase
      .from('session_participants')
      .select('*', { count: 'exact', head: true })
      .eq('user_id', user?.id)

    const { count: listingsCount } = await supabase
      .from('marketplace')
      .select('*', { count: 'exact', head: true })
      .eq('seller_id', user?.id)

    setStats({
      sessionsJoined: sessionsCount || 0,
      playersFound: 5,
      listings: listingsCount || 0,
      posts: 8
    })

    const today = new Date().toISOString().split('T')[0]
    const { data: sessions } = await supabase
      .from('sports_sessions')
      .select('*')
      .gte('session_date', today)
      .order('session_date', { ascending: true })
      .limit(4)
    setUpcomingSessions(sessions || [])
    setLoading(false)
  }

  if (loading) {
    return (
      <div style={{
        minHeight: '100vh',
        background: '#0a0a0a',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        color: 'white'
      }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{
            width: '48px',
            height: '48px',
            border: '4px solid #c8a200',
            borderTopColor: 'transparent',
            borderRadius: '50%',
            margin: '0 auto 16px',
            animation: 'spin 1s linear infinite'
          }} />
          <p style={{ color: '#666' }}>Loading your dashboard...</p>
        </div>
      </div>
    )
  }

  return (
    <div style={{
      minHeight: '100vh',
      background: `url(${IMAGES.dashboardBg}) center/cover no-repeat`,
      backgroundColor: '#0a0a0a',
      color: 'white',
      padding: '24px',
      position: 'relative'
    }}>
      {/* Dark Overlay */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: 'rgba(0,0,0,0.7)',
        zIndex: 0
      }} />

      {/* Animated Background Blobs */}
      <div style={{
        position: 'absolute',
        top: '-20%',
        right: '-10%',
        width: '500px',
        height: '500px',
        borderRadius: '50%',
        background: 'rgba(200,162,0,0.06)',
        filter: 'blur(80px)',
        zIndex: 0,
        animation: 'pulse 4s ease-in-out infinite'
      }} />
      <div style={{
        position: 'absolute',
        bottom: '-30%',
        left: '-10%',
        width: '600px',
        height: '600px',
        borderRadius: '50%',
        background: 'rgba(128,90,213,0.04)',
        filter: 'blur(80px)',
        zIndex: 0,
        animation: 'pulse 4s ease-in-out infinite 1s'
      }} />

      {/* Content */}
      <div style={{
        maxWidth: '1200px',
        margin: '0 auto',
        position: 'relative',
        zIndex: 1
      }}>
        {/* Welcome Section */}
        <div style={{ marginBottom: '32px' }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '12px',
            marginBottom: '8px'
          }}>
            <div style={{
              padding: '8px',
              background: 'rgba(200,162,0,0.1)',
              borderRadius: '12px',
              border: '1px solid rgba(200,162,0,0.2)'
            }}>
              <span style={{ fontSize: '18px' }}>✨</span>
            </div>
            <span style={{
              color: '#c8a200',
              fontSize: '12px',
              fontWeight: '600',
              letterSpacing: '2px',
              textTransform: 'uppercase'
            }}>
              Dashboard
            </span>
          </div>
          <h1 style={{
            fontSize: 'clamp(28px, 5vw, 48px)',
            fontWeight: 'bold',
            color: 'white',
            marginBottom: '4px'
          }}>
            Welcome back,{' '}
            <span style={{
              background: 'linear-gradient(to right, #c8a200, #FFD700)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
              backgroundClip: 'text'
            }}>
              {profile?.full_name?.split(' ')[0] || 'Player'}
            </span>
            <span style={{ marginLeft: '8px' }}>👋</span>
          </h1>
          <p style={{ color: '#888', fontSize: '18px' }}>Ready to play? Here's what's happening today.</p>
        </div>

        {/* Stats Grid */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
          gap: '16px',
          marginBottom: '32px'
        }}>
          {[
            { label: 'Sessions Joined', value: stats.sessionsJoined, emoji: '📅' },
            { label: 'Players Found', value: stats.playersFound, emoji: '👥' },
            { label: 'Active Listings', value: stats.listings, emoji: '🛒' },
            { label: 'Posts', value: stats.posts, emoji: '📝' },
          ].map((stat, index) => (
            <div
              key={index}
              style={{
                background: 'rgba(13,13,13,0.8)',
                backdropFilter: 'blur(20px)',
                WebkitBackdropFilter: 'blur(20px)',
                border: '1px solid rgba(255,255,255,0.05)',
                borderRadius: '16px',
                padding: '20px',
                transition: 'all 0.3s ease',
                cursor: 'default',
                position: 'relative',
                overflow: 'hidden'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.borderColor = 'rgba(200,162,0,0.4)'
                e.currentTarget.style.transform = 'scale(1.03)'
                e.currentTarget.style.boxShadow = '0 8px 30px rgba(200,162,0,0.1)'
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.borderColor = 'rgba(255,255,255,0.05)'
                e.currentTarget.style.transform = 'scale(1)'
                e.currentTarget.style.boxShadow = 'none'
              }}
            >
              <div style={{
                position: 'absolute',
                top: '-50%',
                right: '-50%',
                width: '80px',
                height: '80px',
                background: 'rgba(255,255,255,0.03)',
                borderRadius: '50%',
                filter: 'blur(20px)'
              }} />
              <div style={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'flex-start',
                position: 'relative'
              }}>
                <div>
                  <p style={{ color: '#666', fontSize: '13px', fontWeight: '500' }}>{stat.label}</p>
                  <p style={{
                    fontSize: '28px',
                    fontWeight: 'bold',
                    color: 'white',
                    marginTop: '4px'
                  }}>
                    {stat.value}
                  </p>
                </div>
                <div style={{
                  padding: '8px 12px',
                  background: 'rgba(200,162,0,0.1)',
                  borderRadius: '10px',
                  fontSize: '20px'
                }}>
                  {stat.emoji}
                </div>
              </div>
              <div style={{
                position: 'absolute',
                bottom: 0,
                left: 0,
                right: 0,
                height: '2px',
                background: 'linear-gradient(to right, transparent, #c8a200, transparent)',
                opacity: 0,
                transition: 'opacity 0.3s'
              }}
              onMouseEnter={(e) => e.currentTarget.style.opacity = '1'}
              onMouseLeave={(e) => e.currentTarget.style.opacity = '0'}
              />
            </div>
          ))}
        </div>

        {/* Feature Cards */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
          gap: '16px',
          marginBottom: '32px'
        }}>
          {[
            { title: 'Find Players', emoji: '👥', path: '/find-players', desc: 'Connect with players near you', color: '#3b82f6' },
            { title: 'Create Session', emoji: '➕', path: '/create-session', desc: 'Organize a sports session', color: '#22c55e' },
            { title: 'Browse Sessions', emoji: '📅', path: '/browse-sessions', desc: 'Find sessions to join', color: '#a855f7' },
            { title: 'Marketplace', emoji: '🛒', path: '/marketplace', desc: 'Buy & sell equipment', color: '#f97316' },
          ].map((card, index) => (
            <Link
              key={card.title}
              to={card.path}
              style={{
                background: 'rgba(13,13,13,0.8)',
                backdropFilter: 'blur(20px)',
                WebkitBackdropFilter: 'blur(20px)',
                border: '1px solid rgba(255,255,255,0.05)',
                borderRadius: '16px',
                padding: '24px',
                textDecoration: 'none',
                color: 'white',
                transition: 'all 0.3s ease',
                position: 'relative',
                overflow: 'hidden',
                display: 'block'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.borderColor = 'rgba(200,162,0,0.5)'
                e.currentTarget.style.transform = 'scale(1.04)'
                e.currentTarget.style.boxShadow = '0 12px 40px rgba(200,162,0,0.15)'
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.borderColor = 'rgba(255,255,255,0.05)'
                e.currentTarget.style.transform = 'scale(1)'
                e.currentTarget.style.boxShadow = 'none'
              }}
            >
              <div style={{
                position: 'absolute',
                top: '-30%',
                right: '-30%',
                width: '120px',
                height: '120px',
                background: `radial-gradient(circle, ${card.color}15, transparent)`,
                borderRadius: '50%',
                filter: 'blur(40px)'
              }} />
              <div style={{ position: 'relative' }}>
                <div style={{
                  padding: '12px',
                  background: `rgba(200,162,0,0.08)`,
                  borderRadius: '12px',
                  width: 'fit-content',
                  marginBottom: '12px',
                  fontSize: '24px',
                  transition: 'transform 0.3s'
                }}
                onMouseEnter={(e) => e.currentTarget.style.transform = 'scale(1.1)'}
                onMouseLeave={(e) => e.currentTarget.style.transform = 'scale(1)'}
                >
                  {card.emoji}
                </div>
                <h3 style={{
                  fontSize: '16px',
                  fontWeight: '600',
                  marginBottom: '4px'
                }}>{card.title}</h3>
                <p style={{ color: '#666', fontSize: '13px' }}>{card.desc}</p>
                <div style={{
                  marginTop: '12px',
                  display: 'flex',
                  alignItems: 'center',
                  color: '#c8a200',
                  fontSize: '13px',
                  fontWeight: '500',
                  opacity: 0,
                  transition: 'opacity 0.3s'
                }}
                onMouseEnter={(e) => e.currentTarget.style.opacity = '1'}
                onMouseLeave={(e) => e.currentTarget.style.opacity = '0'}
                >
                  Explore <span style={{ marginLeft: '4px', transition: 'transform 0.3s' }}>→</span>
                </div>
              </div>
            </Link>
          ))}
        </div>

        {/* Upcoming Sessions */}
        <div>
          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            marginBottom: '16px',
            flexWrap: 'wrap',
            gap: '8px'
          }}>
            <div>
              <h2 style={{
                fontSize: '22px',
                fontWeight: 'bold',
                color: 'white',
                display: 'flex',
                alignItems: 'center',
                gap: '12px'
              }}>
                <span style={{ fontSize: '24px' }}>⏰</span>
                Upcoming Sessions
              </h2>
              <p style={{ color: '#666', fontSize: '13px', marginTop: '2px' }}>Sessions happening soon</p>
            </div>
            <Link
              to="/browse-sessions"
              style={{
                color: '#c8a200',
                fontSize: '13px',
                fontWeight: '500',
                textDecoration: 'none',
                display: 'flex',
                alignItems: 'center',
                gap: '4px',
                transition: 'all 0.3s'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.color = '#FFD700'
                const arrow = e.currentTarget.querySelector('span')
                if (arrow) arrow.style.transform = 'translateX(4px)'
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.color = '#c8a200'
                const arrow = e.currentTarget.querySelector('span')
                if (arrow) arrow.style.transform = 'translateX(0)'
              }}
            >
              View all <span style={{ transition: 'transform 0.3s' }}>→</span>
            </Link>
          </div>

          {upcomingSessions.length === 0 ? (
            <div style={{
              background: 'rgba(13,13,13,0.8)',
              backdropFilter: 'blur(20px)',
              border: '1px solid rgba(255,255,255,0.05)',
              borderRadius: '16px',
              padding: '48px',
              textAlign: 'center',
              position: 'relative',
              overflow: 'hidden'
            }}>
              <div style={{
                position: 'absolute',
                top: '-20%',
                right: '-10%',
                width: '200px',
                height: '200px',
                background: 'rgba(200,162,0,0.05)',
                borderRadius: '50%',
                filter: 'blur(60px)'
              }} />
              <div style={{ position: 'relative' }}>
                <div style={{ fontSize: '48px', marginBottom: '12px' }}>🏟️</div>
                <h3 style={{ fontSize: '18px', fontWeight: '600', color: 'white', marginBottom: '4px' }}>
                  No upcoming sessions
                </h3>
                <p style={{ color: '#666', marginBottom: '16px' }}>Be the first to create a session!</p>
                <Link
                  to="/create-session"
                  style={{
                    display: 'inline-flex',
                    alignItems: 'center',
                    gap: '8px',
                    padding: '10px 24px',
                    background: 'linear-gradient(to right, #c8a200, #FFD700)',
                    color: '#0a0a0a',
                    fontWeight: 'bold',
                    borderRadius: '12px',
                    textDecoration: 'none',
                    transition: 'all 0.3s',
                    boxShadow: '0 4px 20px rgba(200,162,0,0.2)'
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.transform = 'scale(1.05)'
                    e.currentTarget.style.boxShadow = '0 8px 30px rgba(200,162,0,0.3)'
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.transform = 'scale(1)'
                    e.currentTarget.style.boxShadow = '0 4px 20px rgba(200,162,0,0.2)'
                  }}
                >
                  ➕ Create Session
                </Link>
              </div>
            </div>
          ) : (
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
              gap: '12px'
            }}>
              {upcomingSessions.map((session) => {
                const { count: participantCount } = session.session_participants?.[0] || { count: 0 }
                const isFull = participantCount >= session.max_participants
                const progress = (participantCount / session.max_participants) * 100

                return (
                  <div
                    key={session.id}
                    style={{
                      background: 'rgba(13,13,13,0.8)',
                      backdropFilter: 'blur(20px)',
                      border: '1px solid rgba(255,255,255,0.05)',
                      borderRadius: '16px',
                      padding: '20px',
                      transition: 'all 0.3s ease',
                      position: 'relative',
                      overflow: 'hidden'
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.borderColor = 'rgba(200,162,0,0.3)'
                      e.currentTarget.style.transform = 'scale(1.02)'
                      e.currentTarget.style.boxShadow = '0 8px 30px rgba(200,162,0,0.08)'
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.borderColor = 'rgba(255,255,255,0.05)'
                      e.currentTarget.style.transform = 'scale(1)'
                      e.currentTarget.style.boxShadow = 'none'
                    }}
                  >
                    <div style={{
                      position: 'absolute',
                      top: '-20%',
                      right: '-20%',
                      width: '100px',
                      height: '100px',
                      background: 'rgba(255,255,255,0.02)',
                      borderRadius: '50%',
                      filter: 'blur(30px)'
                    }} />
                    <div style={{ position: 'relative' }}>
                      <div style={{
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'flex-start',
                        marginBottom: '8px'
                      }}>
                        <span style={{
                          fontSize: '18px',
                          fontWeight: 'bold',
                          color: 'white'
                        }}>
                          {session.sport_type}
                        </span>
                        {isFull ? (
                          <span style={{
                            padding: '2px 12px',
                            background: 'rgba(239,68,68,0.2)',
                            color: '#f87171',
                            fontSize: '11px',
                            fontWeight: '600',
                            borderRadius: '20px',
                            border: '1px solid rgba(239,68,68,0.3)'
                          }}>
                            🔴 Full
                          </span>
                        ) : (
                          <span style={{
                            padding: '2px 12px',
                            background: 'rgba(34,197,94,0.15)',
                            color: '#4ade80',
                            fontSize: '11px',
                            fontWeight: '600',
                            borderRadius: '20px',
                            border: '1px solid rgba(34,197,94,0.2)'
                          }}>
                            {session.max_participants - participantCount} spots left
                          </span>
                        )}
                      </div>
                      <div style={{ marginBottom: '8px' }}>
                        <p style={{
                          color: '#aaa',
                          fontSize: '14px',
                          display: 'flex',
                          alignItems: 'center',
                          gap: '6px',
                          marginBottom: '2px'
                        }}>
                          <span>📍</span> {session.location}
                        </p>
                        <p style={{
                          color: '#666',
                          fontSize: '13px',
                          display: 'flex',
                          alignItems: 'center',
                          gap: '6px'
                        }}>
                          <span>📅</span> {session.session_date} at {session.session_time.substring(0, 5)}
                        </p>
                      </div>
                      <div>
                        <div style={{
                          display: 'flex',
                          justifyContent: 'space-between',
                          fontSize: '11px',
                          color: '#555',
                          marginBottom: '4px'
                        }}>
                          <span>{participantCount} players</span>
                          <span>{session.max_participants} max</span>
                        </div>
                        <div style={{
                          width: '100%',
                          height: '4px',
                          background: 'rgba(255,255,255,0.05)',
                          borderRadius: '2px',
                          overflow: 'hidden'
                        }}>
                          <div style={{
                            width: `${Math.min(progress, 100)}%`,
                            height: '100%',
                            background: isFull 
                              ? 'linear-gradient(to right, #ef4444, #dc2626)'
                              : 'linear-gradient(to right, #c8a200, #FFD700)',
                            borderRadius: '2px',
                            transition: 'width 1s ease'
                          }} />
                        </div>
                      </div>
                      <Link
                        to={`/session/${session.id}`}
                        style={{
                          display: 'block',
                          textAlign: 'center',
                          marginTop: '12px',
                          padding: '6px 0',
                          background: 'rgba(200,162,0,0.08)',
                          color: '#c8a200',
                          border: '1px solid rgba(200,162,0,0.15)',
                          borderRadius: '10px',
                          textDecoration: 'none',
                          fontSize: '13px',
                          fontWeight: '500',
                          transition: 'all 0.3s'
                        }}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.background = '#c8a200'
                          e.currentTarget.style.color = '#0a0a0a'
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.background = 'rgba(200,162,0,0.08)'
                          e.currentTarget.style.color = '#c8a200'
                        }}
                      >
                        View Session
                      </Link>
                    </div>
                  </div>
                )
              })}
            </div>
          )}
        </div>

        {/* Footer */}
        <div style={{
          marginTop: '48px',
          textAlign: 'center'
        }}>
          <div style={{
            display: 'inline-flex',
            alignItems: 'center',
            gap: '8px',
            padding: '6px 16px',
            background: 'rgba(255,255,255,0.03)',
            backdropFilter: 'blur(10px)',
            border: '1px solid rgba(255,255,255,0.05)',
            borderRadius: '20px'
          }}>
            <span style={{ color: '#444', fontSize: '11px' }}>⚡ TeamSynk v2.0</span>
            <span style={{
              width: '4px',
              height: '4px',
              background: '#c8a200',
              borderRadius: '50%'
            }} />
            <span style={{ color: '#444', fontSize: '11px' }}>Premium</span>
          </div>
        </div>
      </div>

      {/* Keyframe Animations */}
      <style>{`
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        @keyframes pulse {
          0%, 100% { transform: scale(1); opacity: 0.6; }
          50% { transform: scale(1.1); opacity: 1; }
        }
      `}</style>
    </div>
  )
}
